  ('immigration-1aab856d-moex-00430', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於公務員之懲戒，下列敘述何者錯誤？', '["受免除職務處分者，不得再任用為公務員", "應受懲戒行為，自行為終了之日起至案件繫屬懲戒法院之日止，已逾10年者，不得予以休職之 懲戒", "停職亦屬於對公務員之懲戒處分", "懲戒法院採二審制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00431', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '公務員甲因超時服勤多年，未獲適當評價與補償，認明顯違法侵害個人健康權與服公職權，甲得 採取下列何種救濟程序？', '["向地方法院行政訴訟庭起訴", "向民事法院申請調解", "向公務人員保障暨培訓委員會提起復審", "向服務機關之上級機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00432', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '長官如要求公務人員從事違反公務人員行政中立法之行為時，公務人員依法可採取的作為，下列 何者錯誤？', '["長官命令如涉及監督範圍內事項，應就違法情事向長官報告", "得檢具相關事證向該長官之上級長官提出報告，由上級長官依法處理", "公務人員得逕向監察院提出檢舉", "長官命令如涉及監督範圍內事項，該命令違反刑法時，公務人員得拒絕服從"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00433', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '關於法規命令之無效，下列敘述何者錯誤？', '["法規命令之一部分無效者，全部無效", "法規命令之訂定依法應經其他機關核准，而未經核准者，無效", "法規命令之一部分無效，除去該無效部分，法規命令顯失規範目的者，全部無效", "法規命令無法律之授權而剝奪或限制人民之自由、權利者，無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00434', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '行政機關訂定法規命令，除法定事由外，應依行政程序法所定程序為之。下列何者非屬該除外之 法定事由？', '["軍事事項", "外交事項", "涉及經濟貿易之重大事項", "涉及國家機密之重大事項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00435', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者為行政處分？', '["行政院海洋委員會發布海洋環境管制標準", "臺北市政府衛生局公布食品衛生稽查資訊", "臺中市政府環保局以通知書方式對空污違規者予以舉發", "新北市政府所屬戶政事務所施行戶口普查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00436', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '行政機關以書面以外方式作為之行政處分，相對人可否要求作成書面？', '["因屬機關裁量權範圍，故作成後即不得再要求作成書面", "有正當理由即可要求機關作成書面", "人民一律有權要求作成書面處分，機關不得拒絕", "相對人提起訴願，始可要求機關作成書面"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00437', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者非屬行政處分撤銷之可能法律效果？', '["原行政處分溯及失效", "給予相對人信賴利益補償", "發生公法上不當得利", "轉換成他種行政處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00438', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何種行政契約，違反現行法令？', '["行政機關與人民訂定行政契約，行政機關嗣後為防止發生重大公益危害，於必要範圍內單方調 整該行政契約之內容", "公立學校與考生甲就指考成績締結行政契約，同意提高甲之總成績二級分", "A、B均為行政機關，為明確雙方行政法關係之權利義務，故於訂定行政契約時，以書面為之", "市政府經市長認可後，與人民乙簽訂之行政契約，可約定於債務人不為給付時，債權人得以該 契約為強制執行之執行名義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00439', 'immigration-1aab856d', 'immigration-1aab856d-moex-111-3082b5f1', 'sub-immigration-1aab856d-05', NULL, 'single_choice', '下列何者非屬行政事實行為？', '["縣市政府興建道路橋樑行為", "行政機關對於申請案件處理經過之說明", "主管機關拆除違章建築之行為", "禁止停車之交通標線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:55+00:00", "source_pdf_sha1": "7ef9e0f05084", "answer_pdf_sha1": "97690dd86af8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "637", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
